    print("=" * 60)
    print("SAML Service Provider starting...")
    print(f"  Entity ID: {SAML_SETTINGS['sp']['entity_id']}")
    print(f"  ACS URL:   {SAML_SETTINGS['sp']['acs_url']}")
    print(f"  IdP SSO:   {SAML_SETTINGS['idp']['sso_url']}")
    print("=" * 60)
    print("\nNOTE: Update SAML_SETTINGS with your actual IdP configuration")
    print("      and IdP X.509 certificate before production use.\n")
    app.run(host="0.0.0.0", port=5000, debug=True)